/**
 * Local timer via performance.now(); USB buzzer = Space / Enter (keydown).
 * QR PNG is generated by GET /api/qr (server-side).
 */

const TARGET_MS = 10000;

/**
 * Celebration rules: `scoreMs` is how far off 10.000 s the player was (lower is better).
 * First matching rule wins (compare `scoreMs <= maxScoreMs`). Use `Infinity` on the last row as a catch-all.
 *
 * `scenario`: rocket animation id — "great" | "meh" | "fail" (see `/rocket` demo).
 * `caption`: short line under the score (German UI).
 */
const ROCKET_SCORE_RULES = [
  { maxScoreMs: 750, scenario: "great", caption: "Glückwunsch — fast perfekt!" },
  { maxScoreMs: 1700, scenario: "meh", caption: "Solide — nächstes Mal noch genauer." },
  { maxScoreMs: Infinity, scenario: "fail", caption: "Übung macht den Meister!" },
];

/** @type {Promise<void>} */
let rocketCelebrationReady = Promise.resolve();

/**
 * @param {number} scoreMs
 * @returns {(typeof ROCKET_SCORE_RULES)[number] | null}
 */
function ruleForScore(scoreMs) {
  for (const rule of ROCKET_SCORE_RULES) {
    if (scoreMs <= rule.maxScoreMs) {
      return rule;
    }
  }
  const last = ROCKET_SCORE_RULES[ROCKET_SCORE_RULES.length - 1];
  return last ?? null;
}

function initGameRocketCelebration() {
  const wrap = document.getElementById("game-rocket-wrap");
  if (!wrap || typeof window.mountRocketStage !== "function") return;
  rocketCelebrationReady = fetch("/partials/rocket-stage.html")
    .then((r) => {
      if (!r.ok) throw new Error("rocket partial missing");
      return r.text();
    })
    .then((html) => {
      wrap.innerHTML = html;
      window.mountRocketStage(wrap);
      if (typeof window.resetRocketStage === "function") {
        window.resetRocketStage();
      }
    })
    .catch(() => {
      /* Celebration is optional; game works without it */
    });
}

/**
 * @param {number} scoreMs
 */
function triggerRocketForScore(scoreMs) {
  const rule = ruleForScore(scoreMs);
  if (!rule) return;
  rocketCelebrationReady.then(() => {
    if (typeof window.playRocketScenario !== "function") return;
    const cap = document.getElementById("game-rocket-caption");
    if (cap) {
      if (rule.caption) {
        cap.textContent = rule.caption;
        cap.hidden = false;
      } else {
        cap.textContent = "";
        cap.hidden = true;
      }
    }
    window.playRocketScenario(rule.scenario);
  });
}

/** @type {'idle' | 'running' | 'postPlay'} */
let state = "idle";
let startMark = 0;
let lastElapsedMs = 0;
let lastScoreMs = 0;

const el = {
  root: document.getElementById("app-root"),
  hint: document.getElementById("state-hint"),
  buzzer: document.getElementById("buzzer-btn"),
  buzzerLabel: document.getElementById("buzzer-label"),
  controlsPanel: document.getElementById("game-panel-controls"),
  resultPanel: document.getElementById("game-panel-result"),
  resultBlock: document.getElementById("result-block"),
  resultDelta: document.getElementById("result-delta"),
  resultElapsed: document.getElementById("result-elapsed"),
  qrHost: document.getElementById("qr-host"),
  qrBlock: document.getElementById("qr-block"),
  surveyLink: document.getElementById("survey-link"),
  surveyUrlDetails: document.getElementById("survey-url-details"),
  surveyUrlFull: document.getElementById("survey-url-full"),
  surveyError: document.getElementById("survey-error"),
  btnAgain: document.getElementById("btn-again"),
  gameRocketCaption: document.getElementById("game-rocket-caption"),
  lbEmptyAll: document.getElementById("leaderboard-empty-all"),
  lbListAll: document.getElementById("leaderboard-list-all"),
  lbEmptyDay: document.getElementById("leaderboard-empty-day"),
  lbListDay: document.getElementById("leaderboard-list-day"),
  lbEmptyWeek: document.getElementById("leaderboard-empty-week"),
  lbListWeek: document.getElementById("leaderboard-list-week"),
};

function setState(next) {
  state = next;
  render();
}

/**
 * Controls card shares the slot with the Ergebnis/QR card: hidden while results are shown.
 */
function updateControlsPanelVisibility() {
  if (!el.controlsPanel) return;
  el.controlsPanel.hidden = state === "postPlay";
}

function render() {
  const showResult = state === "postPlay";
  if (el.resultPanel) {
    el.resultPanel.hidden = !showResult;
  } else {
    el.resultBlock.hidden = !showResult;
  }
  el.buzzer.disabled = state === "postPlay";
  updateControlsPanelVisibility();

  if (state === "idle") {
    if (typeof window.resetRocketStage === "function") {
      window.resetRocketStage();
    }
  } else if (state === "running") {
    if (typeof window.setRocketReadyForLaunch === "function") {
      window.setRocketReadyForLaunch();
    }
  }

  if (state === "idle") {
    el.buzzerLabel.textContent = "START";
    el.buzzer.setAttribute("aria-label", "Starten");
    el.hint.textContent = "Zwei Drücke: Start, dann Stopp.";
  } else if (state === "running") {
    el.buzzerLabel.textContent = "STOP";
    el.buzzer.setAttribute("aria-label", "Stoppen");
    el.hint.textContent = "Zähle mit …";
  } else {
    el.buzzer.setAttribute("aria-label", "Runde beendet");
    el.hint.textContent = "QR-Code wird geladen …";
  }
}

function isBuzzerKey(e) {
  return e.code === "Space" || e.code === "Enter";
}

/**
 * Synthetic events (e.g. element.click() from DevTools) are not trusted — ignore for anti-abuse.
 * @param {Event | undefined} ev
 */
function onBuzzerAction(ev) {
  if (!ev || ev.isTrusted !== true) {
    return;
  }
  if (state === "postPlay") {
    return;
  }

  if (state === "idle") {
    startMark = performance.now();
    setState("running");
    return;
  }

  if (state === "running") {
    const elapsed = performance.now() - startMark;
    lastElapsedMs = elapsed;
    lastScoreMs = Math.round(Math.abs(elapsed - TARGET_MS));
    setState("postPlay");
    el.resultDelta.textContent = `${lastScoreMs} ms daneben`;
    el.resultElapsed.textContent = `Gestoppt bei ${(elapsed / 1000).toFixed(3)} s`;
    triggerRocketForScore(lastScoreMs);
    showQrForScore(lastScoreMs, Math.round(elapsed));
    queueMicrotask(() => el.btnAgain.focus({ preventScroll: true }));
    return;
  }
}

function resetSurveyUi() {
  el.surveyLink.hidden = true;
  el.surveyLink.href = "#";
  el.surveyUrlDetails.hidden = true;
  el.surveyUrlFull.textContent = "";
  el.surveyError.hidden = true;
  el.surveyError.textContent = "";
  if (el.qrBlock) el.qrBlock.hidden = true;
}

async function showQrForScore(scoreMs, elapsedRounded) {
  el.qrHost.replaceChildren();
  resetSurveyUi();
  const base = `${window.location.origin}/survey`;
  let token;
  try {
    const r = await fetch("/api/mint-survey-token", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        score_ms: scoreMs,
        elapsed_ms: elapsedRounded,
      }),
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok || !data.token) {
      throw new Error("mint_failed");
    }
    token = data.token;
  } catch {
    el.surveyError.textContent =
      "Ergebnis konnte nicht signiert werden — bitte Seite neu laden und erneut spielen.";
    el.surveyError.hidden = false;
    if (el.qrBlock) el.qrBlock.hidden = false;
    el.hint.textContent = "Formular-Link konnte nicht erstellt werden — siehe Hinweis unten.";
    return;
  }
  const params = new URLSearchParams({ t: token });
  const url = `${base}?${params.toString()}`;
  el.surveyLink.href = url;
  el.surveyLink.hidden = false;
  el.surveyUrlFull.textContent = url;
  el.surveyUrlDetails.hidden = false;

  const img = document.createElement("img");
  const qrPx = 480;
  img.width = qrPx;
  img.height = qrPx;
  img.alt = "QR-Code zum Formular";
  img.src = `/api/qr?u=${encodeURIComponent(url)}`;
  /**
   * @param {string} [hint] — defaults to scan instruction when QR is usable
   */
  function revealQrBlock(hint) {
    if (el.qrBlock) el.qrBlock.hidden = false;
    el.hint.textContent =
      hint ?? "Scanne den QR-Code für die Bestenliste.";
  }
  img.addEventListener(
    "load",
    () => {
      revealQrBlock();
    },
    { once: true }
  );
  img.addEventListener("error", () => {
    el.qrHost.replaceChildren();
    const p = document.createElement("p");
    p.className = "survey-fallback-msg";
    p.textContent = "QR konnte nicht geladen werden — Link unten öffnen.";
    el.qrHost.appendChild(p);
    el.surveyUrlDetails.open = true;
    revealQrBlock("QR-Anzeige fehlgeschlagen — Link unten zum Formular nutzen.");
  });
  el.qrHost.appendChild(img);
  if (img.complete && img.naturalWidth > 0) {
    revealQrBlock();
  }
}

function onKeyDown(e) {
  if (!isBuzzerKey(e)) return;
  if (e.repeat) return;
  if (e.isTrusted !== true) return;
  if (state === "postPlay") {
    return;
  }
  e.preventDefault();
  onBuzzerAction(e);
}

el.buzzer.addEventListener("click", (e) => onBuzzerAction(e));
el.btnAgain.addEventListener("click", (e) => {
  if (!e.isTrusted) {
    return;
  }
  setState("idle");
  el.qrHost.replaceChildren();
  resetSurveyUi();
  if (el.gameRocketCaption) {
    el.gameRocketCaption.textContent = "";
    el.gameRocketCaption.hidden = true;
  }
});

window.addEventListener("keydown", onKeyDown);

el.root.focus({ preventScroll: true });
setState("idle");
initGameRocketCelebration();

/**
 * @param {unknown[]} entries
 */
function sortLeaderboardEntries(entries) {
  return [...entries].sort((a, b) => {
    const da = Number(a.score_ms);
    const db = Number(b.score_ms);
    const na = Number.isFinite(da) ? da : Infinity;
    const nb = Number.isFinite(db) ? db : Infinity;
    if (na !== nb) return na - nb;
    return String(a.submitted_at || "").localeCompare(String(b.submitted_at || ""));
  });
}

/**
 * @param {unknown[]} entries
 * @param {HTMLElement | null} emptyEl
 * @param {HTMLOListElement | null} listEl
 */
function renderLeaderboardBlock(entries, emptyEl, listEl) {
  if (!emptyEl || !listEl) return;
  if (entries.length === 0) {
    emptyEl.hidden = false;
    listEl.hidden = true;
    return;
  }
  emptyEl.hidden = true;
  listEl.hidden = false;
  listEl.replaceChildren();
  entries.forEach((row, i) => {
    const li = document.createElement("li");
    const name = row.display || "—";
    li.innerHTML = `
        <span class="lb-rank">${i + 1}.</span>
        <span class="lb-name" title="${escapeAttr(name)}">${escapeHtml(name)}</span>
        <span class="lb-score">${row.score_ms} ms</span>
      `;
    listEl.appendChild(li);
  });
}

async function fetchLeaderboard() {
  const limit = 15;
  const load = async (period) => {
    const q =
      period === "all" ? "" : `&period=${encodeURIComponent(period)}`;
    const res = await fetch(`/api/leaderboard?limit=${limit}${q}`, {
      cache: "no-store",
    });
    if (!res.ok) return [];
    const data = await res.json();
    return sortLeaderboardEntries(data.entries || []);
  };
  try {
    const [all, day, week] = await Promise.all([
      load("all"),
      load("day"),
      load("week"),
    ]);
    renderLeaderboardBlock(all, el.lbEmptyAll, el.lbListAll);
    renderLeaderboardBlock(day, el.lbEmptyDay, el.lbListDay);
    renderLeaderboardBlock(week, el.lbEmptyWeek, el.lbListWeek);
  } catch (_) {
    /* ignore */
  }
}

function escapeHtml(s) {
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function escapeAttr(s) {
  return escapeHtml(s).replace(/'/g, "&#39;");
}

const lbTabs = /** @type {HTMLButtonElement[]} */ ([
  document.getElementById("lb-tab-all"),
  document.getElementById("lb-tab-day"),
  document.getElementById("lb-tab-week"),
].filter(Boolean));

const lbPanels = /** @type {HTMLElement[]} */ ([
  document.getElementById("lb-panel-all"),
  document.getElementById("lb-panel-day"),
  document.getElementById("lb-panel-week"),
].filter(Boolean));

const LB_TAB_STORAGE_KEY = "marketing-time-game:leaderboard-tab";
/** @type {const} */ const LB_TAB_PERIODS = ["all", "day", "week"];

/**
 * @returns {number}
 */
function readStoredLeaderboardTabIndex() {
  try {
    const raw = localStorage.getItem(LB_TAB_STORAGE_KEY);
    if (raw == null || raw === "") return 0;
    const i = LB_TAB_PERIODS.indexOf(raw);
    return i >= 0 ? i : 0;
  } catch {
    return 0;
  }
}

/**
 * @param {number} index
 */
function persistLeaderboardTabIndex(index) {
  const id = LB_TAB_PERIODS[index];
  if (!id) return;
  try {
    localStorage.setItem(LB_TAB_STORAGE_KEY, id);
  } catch {
    /* quota / private mode */
  }
}

/**
 * @param {number} index
 * @param {boolean} [focusTab]
 */
function setLeaderboardTab(index, focusTab) {
  const n = lbTabs.length;
  if (n === 0) return;
  const i = ((index % n) + n) % n;
  lbTabs.forEach((tab, j) => {
    const selected = j === i;
    tab.setAttribute("aria-selected", selected ? "true" : "false");
    tab.tabIndex = selected ? 0 : -1;
  });
  lbPanels.forEach((panel, j) => {
    panel.hidden = j !== i;
  });
  persistLeaderboardTabIndex(i);
  if (focusTab) {
    lbTabs[i]?.focus({ preventScroll: true });
  }
}

function initLeaderboardTabs() {
  if (lbTabs.length !== lbPanels.length || lbTabs.length === 0) return;

  lbTabs.forEach((tab, i) => {
    tab.addEventListener("click", () => setLeaderboardTab(i, false));
    tab.addEventListener("keydown", (e) => {
      if (e.key === "ArrowRight" || e.key === "ArrowDown") {
        e.preventDefault();
        setLeaderboardTab(i + 1, true);
      } else if (e.key === "ArrowLeft" || e.key === "ArrowUp") {
        e.preventDefault();
        setLeaderboardTab(i - 1, true);
      } else if (e.key === "Home") {
        e.preventDefault();
        setLeaderboardTab(0, true);
      } else if (e.key === "End") {
        e.preventDefault();
        setLeaderboardTab(lbTabs.length - 1, true);
      }
    });
  });

  setLeaderboardTab(readStoredLeaderboardTabIndex(), false);
}

initLeaderboardTabs();
fetchLeaderboard();
setInterval(fetchLeaderboard, 10000);
